import { AppBar, Avatar, Badge, Box, Drawer, IconButton, List, ListItem, ListItemIcon, makeStyles, Toolbar, Typography } from '@material-ui/core'
import { AddCircle, Dashboard, ExpandMore, PlaylistAddCheck } from '@material-ui/icons';
import urslogo from '../images/urslogo.png'
import phil from '../images/phil.png'
import React from 'react'
import { useHistory } from 'react-router-dom/cjs/react-router-dom.min';
import { withStyles } from '@material-ui/styles';

const StyledBadge = withStyles((theme) => ({
    badge: {
        backgroundColor: '#44b700',
        color: '#44b700',
        boxShadow: `0 0 0 2px ${theme.palette.background.paper}`,
        '&::after': {
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            borderRadius: '50%',
            animation: '$ripple 1.2s infinite ease-in-out',
            border: '1px solid currentColor',
            content: '""',
        },
    },
    '@keyframes ripple': {
        '0%': {
            transform: 'scale(.8)',
            opacity: 1,
        },
        '100%': {
            transform: 'scale(2.4)',
            opacity: 0,
        },
    },
}))(Badge);

const drawerWidth = 60;

const useStyle = makeStyles(theme => {
    return {
        root: {
            display: 'flex',
            '& .MuiToolbar-root': {
                boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;'
            },
            '& .MuiCard-root': {
                boxShadow: 'rgb(35 68 101 / 5%) 0px 4px 16px, rgb(35 68 101 / 5%) 0px 4px 4px;',
                
    '&:hover': {
        transform: 'rotate(2.5deg)',
        transition: '0.2s'
      },
      backgroundColor: '#ffffff'
            }
        },
        page: {
            background: '#f9fbfd',
            width: '100%',
            padding: theme.spacing(3)
        },
        sidebar: {
            width: drawerWidth
        },
        sidebarSpace: {
            width: drawerWidth,
            background: '#162276',
            color: '#ffffff',
            overflow: 'hidden'
        },
        logoContainer: {
            maxWidth: '40px',
            margin: '2px auto'
        },
        logo: {
            width: '100%',
            paddingTop: '10%'
        },
        appbar: {
            width: `calc(100% - ${drawerWidth}px)`
        },
        toolbar: theme.mixins.toolbar,
        title: {
            flexGrow: 1
        },
        lists: {
            marginTop: '10px'
        }
    }
});


export default function Layout({ children }) {
    const classes = useStyle()
    const history = useHistory()

    const sideLinks = [
        {
            text: 'Dashboard',
            icon: <Dashboard color='error' />,
            path: '/studentDashboard'
        },
        {
            text: 'Subjects',
            icon: <PlaylistAddCheck color='error' />,
            path: '/studentDashboard'
        },
        {
            text: 'Join a Class',
            icon: <AddCircle color='error' />,
            path: '/studentDashboard'
        },
    ]

    return (
        <div className={classes.root}>
            {/* // appbar */}

            <AppBar className={classes.appbar} color='inherit' elevation={0}>
                <Toolbar>
                    <Typography className={classes.title} variant='h5'>
                        URSAC ONLINE
                    </Typography>
                    <IconButton>
                        <StyledBadge
                            overlap="circular"
                            anchorOrigin={{
                                vertical: 'bottom',
                                horizontal: 'right',
                            }}
                            variant="dot"
                        >
                            <Avatar src={phil} />
                        </StyledBadge>
                    </IconButton>
                    <Typography variant='caption'>
                        Cris Philip V. Cajurao
                        <IconButton>
                            <ExpandMore />
                        </IconButton>
                    </Typography>
                </Toolbar>
            </AppBar>

            {/* // sidebar */}

            <Drawer
                className={classes.sidebar}
                variant='permanent'
                anchor='left'
                classes={{ paper: classes.sidebarSpace }}
            >
                <div className={classes.logoContainer}>
                    <Box >
                        <img className={classes.logo} src={urslogo} alt="URSAC Online logo" />
                    </Box>
                </div>
                {/* List links */}
                <List className={classes.lists}>
                    {sideLinks.map(sideLink => (
                        <ListItem
                            button
                            key={sideLink.text}
                            onClick={() => history.push(sideLink.path)}
                        >

                            <ListItemIcon>
                                {sideLink.icon}
                            </ListItemIcon>
                            {/* <ListItemText>
                                    {sideLink.text}
                                </ListItemText> */}
                        </ListItem>
                    ))}
                </List>

            </Drawer>

            <div className={classes.page}>
                <div className={classes.toolbar} elevation={0}></div>
                {children}
            </div>
        </div>
    )
}
